class Solution:
    def fillCups(self, amount):
        a = list(amount)
        secs = 0
        while sum(a) > 0:
            a.sort()
            if a[1] == 0:
                secs += a[2]
                break
            a[2] -= 1
            a[1] -= 1
            secs += 1
        return secs

